openscad:
$fn=60;
case_diameter=40;//[20:1:80]
case_height=6;//[3:0.5:12]
dial_diameter=36;//[15:1:70]
marker_length=2.5;//[1:0.5:5]
marker_width=1.2;//[0.5:0.2:3]
minute_length=14;//[5:1:30]
minute_width=1.8;//[0.8:0.2:4]
hour_length=9;//[3:1:20]
hour_width=2.4;//[1:0.2:5]
hand_height=1.5;//[0.5:0.2:4]

color("black")
difference(){
  cylinder(d=case_diameter,h=case_height);
  translate([0,0,case_height-1.5])
    cylinder(d=dial_diameter+1,h=case_height);
}

color("white")
translate([0,0,case_height-1.5])
  cylinder(d=dial_diameter,h=1.6);

color("black")
for(i=[0:11]){
  rotate([0,0,i*30])
    translate([dial_diameter/2-marker_length-1,0,case_height-1.4])
      cube([marker_length,marker_width,1.6],center=true);
}

module watch_hand(len,wid){
  linear_extrude(hand_height)
    hull(){
      circle(d=wid);
      translate([len-wid/2,0])circle(d=wid*0.4);
    }
}

color("black")
translate([0,0,case_height-0.1])
  rotate([0,0,30])
    watch_hand(minute_length,minute_width);

color("black")
translate([0,0,case_height-0.1])
  rotate([0,0,120])
    watch_hand(hour_length,hour_width);
